            const col = s.kind === "door" ? 0x8b5a2b : s.kind === "window" ? 0x9fd3e0 : s.kind === "beam" ? 0x9aa0a6 : 0xcbb89a;
            const sw = +s.width || 800, sh = +s.height || (s.kind === "window" ? 1200 : s.kind === "beam" ? (+s.drop || 300) : 2000), pos = +s.pos || 200;
