          const m = new THREE.Mesh(new THREE.SphereGeometry(30, 12, 12), new THREE.MeshStandardMaterial({ color: col, emissive: col, emissiveIntensity: 0.35 })); m.position.set(w3[0], w3[1], w3[2]); m.castShadow = true; scene.add(m);
