            for (let b2 = 0; b2 < 2; b2++) { const g5 = mkG(pl, cl, D * 0.4, 760 + b2 * 420); g5.add(mBox(c.w - 70, 110, D * 0.62, WIREM())); slideMech(g5, pl, D * 0.55, 1.3 + b2 * 0.25); }
