      p.push(`<text x="${(x0 + wpx / 2).toFixed(1)}" y="${(y0 + loftPx / 2 + 3).toFixed(1)}" fill="#a16207" font-size="9" font-weight="600" text-anchor="middle">LOFT (split) ${opt.loftH} mm</text>`);
