    p.push(`<text x="${(bx + bw / 2).toFixed(1)}" y="${(y0 + (byBottom - y0) / 2 + 3).toFixed(1)}" fill="#c2410c" font-size="8" font-weight="700" text-anchor="middle">BEAM ↓${beam.proj}</text>`);
